# Solution: Raising and Handling Exceptions

def validate_positive(n):
    """Return n if positive, else raise ValueError."""
    if not isinstance(n, (int, float)):
        raise TypeError("Expected a number")
    if n <= 0:
        raise ValueError(f"Expected positive number, got {n}")
    return n

def safe_sqrt(n):
    """Return square root of n using n**0.5. Raise ValueError for negative."""
    if not isinstance(n, (int, float)):
        raise TypeError("Expected a number")
    if n < 0:
        raise ValueError(f"Cannot compute square root of negative number: {n}")
    return n ** 0.5

def validate_range(value, min_val, max_val):
    """Return value if in [min_val, max_val], else raise ValueError."""
    if value < min_val or value > max_val:
        raise ValueError(f"Value {value} out of range [{min_val}, {max_val}]")
    return value

def require_type(value, expected_type):
    """Return value if isinstance check passes, else raise TypeError."""
    if not isinstance(value, expected_type):
        raise TypeError(f"Expected {expected_type.__name__}, got {type(value).__name__}")
    return value

